UPDATE words SET example_en_2 = 'He enjoyed a brief sojourn in a Provençal village.', example_ko_2 = '그는 프로방스 마을에서 잠깐의 체류를 즐겼어요.', example_en_3 = 'Her sojourn in Japan changed her perspective on simplicity.', example_ko_3 = '일본에서의 체류가 단순함에 대한 그녀의 시각을 바꿔줬어요.', example_en_4 = 'A short sojourn in the mountains restored my energy.', example_ko_4 = '산에서의 짧은 체류가 저의 에너지를 회복시켜줬어요.', example_en_5 = 'The poet''s sojourn in Rome became his most productive period.', example_ko_5 = '그 시인의 로마 체류 기간은 가장 창의적인 시기가 됐어요.' WHERE id = 'w_travel_C1_03';
UPDATE words SET example_en_2 = 'He described himself as a modern vagabond.', example_ko_2 = '그는 자신을 현대의 방랑자라고 표현했어요.', example_en_3 = 'The vagabond lifestyle suited his restless spirit.', example_ko_3 = '방랑자적 생활 방식이 그의 불안한 영혼에 잘 맞았어요.', example_en_4 = 'She wrote songs about her life as a vagabond musician.', example_ko_4 = '그녀는 방랑 음악가로서의 삶에 대한 노래를 썼어요.', example_en_5 = 'The novel follows a young vagabond across war-torn Europe.', example_ko_5 = '그 소설은 전쟁으로 황폐해진 유럽을 헤매는 젊은 방랑자를 따라가요.' WHERE id = 'w_travel_C1_04';
