UPDATE words SET example_en_2 = 'She likes to perambulate the old quarter every morning.', example_ko_2 = '그녀는 매일 아침 구시가지를 산책하는 걸 좋아해요.', example_en_3 = 'He would often perambulate the city in search of inspiration.', example_ko_3 = '그는 영감을 찾아 도시를 자주 산책했어요.', example_en_4 = 'The couple perambulated the botanical garden hand in hand.', example_ko_4 = '그 커플은 손을 잡고 식물원을 천천히 거닐었어요.', example_en_5 = 'Let us perambulate rather than rush through the neighbourhood.', example_ko_5 = '서두르지 말고 동네를 천천히 걸어봐요.' WHERE id = 'w_travel_C1_11';
