UPDATE words SET example_en_2 = 'As an expatriate, she celebrated Korean holidays from afar.', example_ko_2 = '해외 거주자로서 그녀는 먼 곳에서 한국 명절을 기념했어요.', example_en_3 = 'The city has a large expatriate community.', example_ko_3 = '그 도시에는 해외 거주자 커뮤니티가 큰 편이에요.', example_en_4 = 'Being an expatriate taught him to adapt quickly.', example_ko_4 = '해외 거주자 생활을 통해 빠르게 적응하는 법을 배웠어요.', example_en_5 = 'Many expatriates find it hard to return after years abroad.', example_ko_5 = '많은 해외 거주자들이 오랜 외국 생활 후 귀국이 힘들다고 느껴요.' WHERE id = 'w_travel_C1_14';
UPDATE words SET example_en_2 = 'Nomadism was the dominant way of life on the steppe.', example_ko_2 = '유목주의는 초원 지대의 지배적인 생활 방식이었어요.', example_en_3 = 'Digital nomadism has blurred the line between work and travel.', example_ko_3 = '디지털 유목주의는 일과 여행의 경계를 흐리게 만들었어요.', example_en_4 = 'She wrote a thesis on the cultural roots of nomadism.', example_ko_4 = '그녀는 유목주의의 문화적 뿌리에 대한 논문을 썼어요.', example_en_5 = 'Modern nomadism is facilitated by remote working tools.', example_ko_5 = '현대 유목주의는 원격 근무 도구에 의해 가능해졌어요.' WHERE id = 'w_travel_C1_15';
UPDATE words SET example_en_2 = 'The river meanders through a wide, flat valley.', example_ko_2 = '강이 넓고 평평한 계곡을 굽이굽이 흘러요.', example_en_3 = 'I love to meander through local markets with no agenda.', example_ko_3 = '목적 없이 현지 시장을 이리저리 돌아다니는 걸 좋아해요.', example_en_4 = 'The path meanders along the cliff edge.', example_ko_4 = '그 길은 절벽 가장자리를 따라 구불구불 이어져요.', example_en_5 = 'We spent the afternoon meandering through back streets.', example_ko_5 = '오후 내내 골목길을 이리저리 돌아다녔어요.' WHERE id = 'w_travel_C1_16';
UPDATE words SET example_en_2 = 'A month-long sojourn in Kyoto deepened her love of Japan.', example_ko_2 = '교토에서의 한 달 체류가 그녀의 일본 사랑을 더욱 깊게 했어요.', example_en_3 = 'His sojourn at the monastery was a turning point.', example_ko_3 = '수도원에서의 체류는 그에게 전환점이 됐어요.', example_en_4 = 'Even a brief sojourn can leave a lasting impression.', example_ko_4 = '짧은 체류도 오래 지속되는 인상을 남길 수 있어요.', example_en_5 = 'The artist''s sojourn in Paris produced some of her best work.', example_ko_5 = '그 예술가의 파리 체류 기간에 그녀의 최고 작품들이 탄생했어요.' WHERE id = 'w_travel_C1_17';
UPDATE words SET example_en_2 = 'The passengers began to alight at the central station.', example_ko_2 = '승객들이 중앙역에서 내리기 시작했어요.', example_en_3 = 'Please alight from the bus at the front doors only.', example_ko_3 = '버스에서는 앞문으로만 내려주세요.', example_en_4 = 'She chose to alight two stops early to walk the rest.', example_ko_4 = '나머지를 걷기 위해 두 정거장 일찍 내렸어요.', example_en_5 = 'Passengers wishing to alight here should press the bell.', example_ko_5 = '여기서 내리려는 승객은 벨을 눌러 주세요.' WHERE id = 'w_travel_C1_18';
UPDATE words SET example_en_2 = 'Embarkation for the evening cruise begins at seven.', example_ko_2 = '저녁 크루즈 승선은 7시부터 시작해요.', example_en_3 = 'The embarkation process was smooth and well-organised.', example_ko_3 = '승선 절차가 순조롭고 잘 진행됐어요.', example_en_4 = 'All passengers must complete embarkation checks.', example_ko_4 = '모든 승객은 승선 확인을 완료해야 해요.', example_en_5 = 'The port of embarkation was crowded with excited travellers.', example_ko_5 = '출항 항구는 설레는 여행자들로 가득했어요.' WHERE id = 'w_travel_C1_19';
UPDATE words SET example_en_2 = 'The itinerant vendor sold handmade jewellery at every market.', example_ko_2 = '그 유랑 상인은 모든 시장에서 수제 장신구를 팔았어요.', example_en_3 = 'An itinerant vendor appeared at the festival with street food.', example_ko_3 = '유랑 상인이 축제에 길거리 음식을 들고 나타났어요.', example_en_4 = 'The children loved watching the itinerant vendor''s magic show.', example_ko_4 = '아이들은 유랑 상인의 마술 쇼를 보는 걸 좋아했어요.', example_en_5 = 'An itinerant vendor travels from market to market.', example_ko_5 = '유랑 상인은 시장에서 시장으로 이동해요.' WHERE id = 'w_travel_C1_20';
UPDATE words SET example_en_2 = 'As a cosmopolite, she felt at home in any city.', example_ko_2 = '세계시민으로서 그녀는 어느 도시에서도 편안함을 느꼈어요.', example_en_3 = 'A true cosmopolite can navigate any culture with ease.', example_ko_3 = '진정한 세계시민은 어떤 문화도 쉽게 헤쳐나가요.', example_en_4 = 'His cosmopolite outlook informed his writing style.', example_ko_4 = '그의 세계시민적 시각이 글쓰기 방식에 영향을 줬어요.', example_en_5 = 'Years of international travel made him a cosmopolite.', example_ko_5 = '수년간의 국제 여행이 그를 세계시민으로 만들었어요.' WHERE id = 'w_travel_C1_21';
UPDATE words SET example_en_2 = 'Transient populations create unique social dynamics.', example_ko_2 = '일시적 인구는 독특한 사회적 역학을 만들어요.', example_en_3 = 'The transient nature of travel can feel both freeing and unsettling.', example_ko_3 = '여행의 일시적인 특성은 해방감과 불안감을 동시에 줄 수 있어요.', example_en_4 = 'The border town was home to a large transient community.', example_ko_4 = '그 국경 도시는 많은 일시 거주자 커뮤니티의 보금자리였어요.', example_en_5 = 'He found beauty in the transient moments of a long journey.', example_ko_5 = '그는 긴 여정의 순간순간에서 아름다움을 발견했어요.' WHERE id = 'w_travel_C1_22';
UPDATE words SET example_en_2 = 'The heritage trail connects a dozen historic landmarks.', example_ko_2 = '유산 탐방로는 열두 개의 역사적 랜드마크를 이어줘요.', example_en_3 = 'Walking the heritage trail took us three days.', example_ko_3 = '유산 탐방로를 걷는 데 3일이 걸렸어요.', example_en_4 = 'The heritage trail is well signposted and easy to follow.', example_ko_4 = '유산 탐방로는 표지판이 잘 되어 있어서 따라가기 쉬워요.', example_en_5 = 'A guided heritage trail gives context to the buildings you visit.', example_ko_5 = '가이드 유산 탐방은 방문하는 건물에 대한 맥락을 제공해요.' WHERE id = 'w_travel_C1_23';
UPDATE words SET example_en_2 = 'Long tours can lead to itinerary fatigue.', example_ko_2 = '긴 투어는 일정 피로감을 불러올 수 있어요.', example_en_3 = 'She recognised itinerary fatigue when she stopped enjoying sightseeing.', example_ko_3 = '관광을 즐기지 못하게 됐을 때 일정 피로감을 느꼈어요.', example_en_4 = 'Taking rest days helps avoid itinerary fatigue.', example_ko_4 = '휴식일을 두면 일정 피로감을 피하는 데 도움이 돼요.', example_en_5 = 'Itinerary fatigue is a real risk on long-haul group tours.', example_ko_5 = '일정 피로감은 장거리 단체 여행에서 실질적인 위험이에요.' WHERE id = 'w_travel_C1_24';
UPDATE words SET example_en_2 = 'As a xenophile, he was drawn to unfamiliar cultures.', example_ko_2 = '외국 문화를 좋아하는 사람으로서 그는 낯선 문화에 끌렸어요.', example_en_3 = 'Her xenophile nature made her an ideal cultural ambassador.', example_ko_3 = '외국 문화를 좋아하는 그녀의 성격이 이상적인 문화 대사로 만들었어요.', example_en_4 = 'A xenophile thrives on encountering the unfamiliar.', example_ko_4 = '외국 문화를 좋아하는 사람은 낯선 것을 만날 때 행복해요.', example_en_5 = 'Her xenophile tendencies were obvious from her bookshelf.', example_ko_5 = '그녀의 책장만 봐도 외국 문화에 대한 사랑이 느껴졌어요.' WHERE id = 'w_travel_C1_25';
UPDATE words SET example_en_2 = 'I felt disoriented in the dense urban streets.', example_ko_2 = '복잡한 도시 골목에서 방향 감각을 잃었어요.', example_en_3 = 'The lack of signage left us completely disoriented.', example_ko_3 = '표지판이 없어서 완전히 방향을 잃었어요.', example_en_4 = 'Arriving at night can leave you feeling disoriented.', example_ko_4 = '밤에 도착하면 방향 감각을 잃을 수 있어요.', example_en_5 = 'She was disoriented by the time difference.', example_ko_5 = '그녀는 시차 때문에 방향 감각을 잃었어요.' WHERE id = 'w_travel_C1_26';
UPDATE words SET example_en_2 = 'The quest for authentic food led us down narrow alleys.', example_ko_2 = '정통 음식을 향한 탐구가 우리를 좁은 골목으로 이끌었어요.', example_en_3 = 'Her quest for adventure knows no borders.', example_ko_3 = '그녀의 모험을 향한 탐구는 국경을 몰라요.', example_en_4 = 'The hike was less a walk and more a quest.', example_ko_4 = '그 하이킹은 산책이라기보다는 탐험에 가까웠어요.', example_en_5 = 'Every great journey begins as a personal quest.', example_ko_5 = '모든 위대한 여정은 개인적인 탐구로 시작해요.' WHERE id = 'w_travel_C1_27';
UPDATE words SET example_en_2 = 'The pathfinder mapped out the route for the rest of the group.', example_ko_2 = '길안내자가 나머지 그룹을 위해 경로를 안내했어요.', example_en_3 = 'She was the pathfinder who opened new trade routes.', example_ko_3 = '그녀는 새로운 무역 경로를 개척한 개척자였어요.', example_en_4 = 'The app served as a digital pathfinder in unfamiliar cities.', example_ko_4 = '그 앱이 낯선 도시에서 디지털 길 안내자 역할을 했어요.', example_en_5 = 'A good pathfinder anticipates obstacles before they arise.', example_ko_5 = '훌륭한 길안내자는 문제가 생기기 전에 미리 예상해요.' WHERE id = 'w_travel_C1_28';
UPDATE words SET example_en_2 = 'I love to wander through medieval towns with no plan.', example_ko_2 = '계획 없이 중세 마을을 이리저리 돌아다니는 걸 좋아해요.', example_en_3 = 'His mind tends to wander when he travels by train.', example_ko_3 = '기차로 여행할 때 그의 마음은 이리저리 헤매는 경향이 있어요.', example_en_4 = 'We wandered along the riverbank for hours.', example_ko_4 = '몇 시간 동안 강변을 따라 이리저리 걸었어요.', example_en_5 = 'Allow yourself to wander — the best discoveries are unplanned.', example_ko_5 = '이리저리 돌아다녀 보세요. 최고의 발견은 계획 밖에서 일어나요.' WHERE id = 'w_travel_C1_29';
UPDATE words SET example_en_2 = 'The souvenir hunting turned into a half-day adventure.', example_ko_2 = '기념품 찾기가 반나절 모험으로 바뀌었어요.', example_en_3 = 'She is passionate about souvenir hunting in local markets.', example_ko_3 = '그녀는 현지 시장에서 기념품을 찾는 것에 열정적이에요.', example_en_4 = 'Souvenir hunting in vintage shops is more rewarding than tourist traps.', example_ko_4 = '빈티지 가게에서 기념품을 찾는 것이 관광객 상점보다 더 보람있어요.', example_en_5 = 'He spent his last morning on souvenir hunting.', example_ko_5 = '마지막 아침을 기념품 찾기에 쏟았어요.' WHERE id = 'w_travel_C1_30';
UPDATE words SET example_en_2 = 'The frontier town had a wild, lawless energy.', example_ko_2 = '그 변경 마을은 거칠고 무법적인 기운이 있었어요.', example_en_3 = 'Crossing into a new frontier felt like crossing into another world.', example_ko_3 = '새로운 변경 지역으로 들어가는 것은 다른 세계로 넘어가는 것 같았어요.', example_en_4 = 'The scientific expedition pushed to the very frontier of knowledge.', example_ko_4 = '그 과학 탐험대는 지식의 최전선까지 나아갔어요.', example_en_5 = 'Adventure travel often takes place at the frontier.', example_ko_5 = '모험 여행은 종종 변경 지역에서 이루어져요.' WHERE id = 'w_travel_C1_31';
UPDATE words SET example_en_2 = 'The route traverses some spectacular highland terrain.', example_ko_2 = '그 경로는 몇몇 장관을 이루는 고지대를 가로질러요.', example_en_3 = 'We traversed the national park over three gruelling days.', example_ko_3 = '3일간의 힘든 일정으로 국립공원을 가로질렀어요.', example_en_4 = 'The story traverses three generations of one family.', example_ko_4 = '그 이야기는 한 가족의 3대에 걸쳐 있어요.', example_en_5 = 'Her career trajectory traverses journalism, travel writing, and fiction.', example_ko_5 = '그녀의 커리어는 저널리즘, 여행 글쓰기, 소설을 아우르고 있어요.' WHERE id = 'w_travel_C1_32';
UPDATE words SET example_en_2 = 'Try to immerse yourself in the local culture.', example_ko_2 = '현지 문화에 몸을 담가 보세요.', example_en_3 = 'He immersed himself in language learning before the trip.', example_ko_3 = '그는 여행 전에 언어 학습에 푹 빠졌어요.', example_en_4 = 'She fully immersed herself in the community.', example_ko_4 = '그녀는 그 커뮤니티에 완전히 녹아들었어요.', example_en_5 = 'The best way to learn a language is to immerse yourself in it.', example_ko_5 = '언어를 배우는 가장 좋은 방법은 그 언어 속에 빠져드는 것이에요.' WHERE id = 'w_travel_C1_33';
UPDATE words SET example_en_2 = 'Her foray into Southeast Asian cuisine was a revelation.', example_ko_2 = '동남아시아 요리로의 그녀의 탐험은 큰 깨달음이었어요.', example_en_3 = 'His first foray abroad was a disaster but a great learning experience.', example_ko_3 = '해외 첫 모험은 재앙이었지만 훌륭한 학습 경험이었어요.', example_en_4 = 'A brief foray into the backstreets revealed a hidden temple.', example_ko_4 = '뒷골목으로의 짧은 탐험이 숨겨진 사원을 발견하게 해줬어요.', example_en_5 = 'Every foray into a new culture teaches you something about your own.', example_ko_5 = '새로운 문화로의 모든 탐험은 자신의 문화에 대해 무언가를 가르쳐줘요.' WHERE id = 'w_travel_C1_34';
UPDATE words SET example_en_2 = 'She studied cartography to better understand historical exploration.', example_ko_2 = '그녀는 역사적 탐험을 더 잘 이해하기 위해 지도학을 공부했어요.', example_en_3 = 'Advances in cartography transformed navigation at sea.', example_ko_3 = '지도학의 발전이 해상 항법을 혁신했어요.', example_en_4 = 'The cartography of the region has changed with political borders.', example_ko_4 = '그 지역의 지도는 정치적 국경에 따라 바뀌었어요.', example_en_5 = 'Modern cartography relies heavily on satellite data.', example_ko_5 = '현대 지도학은 위성 데이터에 크게 의존해요.' WHERE id = 'w_travel_C1_35';

